  function formatadorSql() {
    html(`<div class="field"><label for="sql-input">Consulta SQL</label><textarea id="sql-input" spellcheck="false">SELECT u.id,u.nome,p.perfil FROM usuarios u LEFT JOIN perfis p ON p.usuario_id=u.id WHERE u.ativo=true AND u.criado_em>=CURRENT_DATE-30 ORDER BY u.nome;</textarea></div><div class="two-col"><div class="field"><label for="sql-case">Palavras-chave</label><select id="sql-case"><option value="upper">MAIÚSCULAS</option><option value="lower">minúsculas</option><option value="keep">Manter</option></select></div><div class="field"><label for="sql-indent">Indentação</label><select id="sql-indent"><option value="2">2 espaços</option><option value="4">4 espaços</option></select></div></div><div class="actions"><button class="btn btn-primary" id="format-sql">Formatar</button><button class="btn btn-secondary" id="minify-sql">Minificar</button><button class="btn btn-secondary" data-copy-target="#sql-output">Copiar</button></div><pre class="output large" id="sql-output"></pre><div class="status" id="status"></div><p class="note">Formatador voltado a consultas comuns. Dialetos e blocos procedurais complexos podem exigir uma ferramenta específica do banco.</p>`);
    const keywords=['select','from','where','left join','right join','inner join','full join','cross join','join','on','group by','order by','having','limit','offset','union all','union','insert into','values','update','set','delete from','and','or','as','distinct','case','when','then','else','end'];
    const protect=(sql)=>{const strings=[];return{value:sql.replace(/'(?:''|[^'])*'|"(?:""|[^"])*"/g,m=>`__STR_${strings.push(m)-1}__`),strings};};
    const restore=(sql,strings)=>sql.replace(/__STR_(\d+)__/g,(_,i)=>strings[Number(i)]);
    const changeCase=(sql)=>{const mode=q('#sql-case').value;if(mode==='keep')return sql;const ordered=[...keywords].sort((a,b)=>b.length-a.length),regex=new RegExp(`\\b(${ordered.map(k=>k.replace(' ','\\s+')).join('|')})\\b`,'gi');return sql.replace(regex,m=>mode==='upper'?m.toUpperCase():m.toLowerCase());};
    const format=()=>{try{const indent=' '.repeat(Number(q('#sql-indent').value)),protectedSql=protect(q('#sql-input').value.trim());let sql=protectedSql.value.replace(/\s+/g,' ').replace(/\s*,\s*/g,', ');sql=changeCase(sql);const main=['SELECT','FROM','WHERE','GROUP BY','ORDER BY','HAVING','LIMIT','OFFSET','UNION ALL','UNION','INSERT INTO','VALUES','UPDATE','SET','DELETE FROM','LEFT JOIN','RIGHT JOIN','INNER JOIN','FULL JOIN','CROSS JOIN','JOIN'];for(const word of main){const rx=new RegExp(`\\s+${word.replace(' ','\\s+')}\\s+`,'gi');sql=sql.replace(rx,`\n${word} `);}sql=sql.replace(/\s+(AND|OR)\s+/gi,`\n${indent}$1 `);sql=sql.replace(/SELECT\s+/i,m=>m).replace(/,\s*/g,`,\n${indent}`);sql=restore(sql.trim(),protectedSql.strings);outputText('#sql-output',sql);showStatus('SQL formatado.','success');trackAction('format_sql');}catch(error){showStatus(error.message,'error');}};
    const minify=()=>{const protectedSql=protect(q('#sql-input').value);outputText('#sql-output',restore(changeCase(protectedSql.value.replace(/\s+/g,' ').trim()),protectedSql.strings));showStatus('SQL minificado.','success');trackAction('minify_sql');};q('#format-sql').addEventListener('click',format);q('#minify-sql').addEventListener('click',minify);format();
  }

  function contrasteCores() {
    html(`<div class="two-col"><div class="field"><label for="color-foreground">Cor do texto</label><div class="color-control"><input id="color-foreground-picker" type="color" value="#16213e"><input class="input" id="color-foreground" value="#16213e" maxlength="7"></div></div><div class="field"><label for="color-background">Cor do fundo</label><div class="color-control"><input id="color-background-picker" type="color" value="#ffffff"><input class="input" id="color-background" value="#ffffff" maxlength="7"></div></div></div><div class="preview-box" id="contrast-preview"><h3>Texto de exemplo</h3><p>Qualidade de software com acessibilidade.</p></div><div class="center"><div class="ratio-result" id="contrast-ratio">—</div><p id="contrast-summary"></p></div><div class="table-wrap"><table><thead><tr><th>Critério</th><th>Resultado</th></tr></thead><tbody id="contrast-table"></tbody></table></div><div class="actions"><button class="btn btn-secondary" id="swap-colors">Trocar cores</button></div><div class="status" id="status"></div>`);
    const validHex=(v)=>/^#[0-9a-f]{6}$/i.test(v);
    const rgb=(hex)=>[parseInt(hex.slice(1,3),16),parseInt(hex.slice(3,5),16),parseInt(hex.slice(5,7),16)];
    const luminance=(hex)=>{const values=rgb(hex).map(v=>{const s=v/255;return s<=.03928?s/12.92:Math.pow((s+.055)/1.055,2.4);});return .2126*values[0]+.7152*values[1]+.0722*values[2];};
    const update=()=>{const fg=q('#color-foreground').value.trim(),bg=q('#color-background').value.trim();if(!validHex(fg)||!validHex(bg))return showStatus('Use cores hexadecimais no formato #RRGGBB.','error');q('#color-foreground-picker').value=fg;q('#color-background-picker').value=bg;const ratio=(Math.max(luminance(fg),luminance(bg))+.05)/(Math.min(luminance(fg),luminance(bg))+.05);q('#contrast-preview').style.color=fg;q('#contrast-preview').style.backgroundColor=bg;q('#contrast-ratio').textContent=`${ratio.toFixed(2)}:1`;const tests=[['Texto normal — WCAG AA',ratio>=4.5],['Texto grande — WCAG AA',ratio>=3],['Texto normal — WCAG AAA',ratio>=7],['Texto grande — WCAG AAA',ratio>=4.5],['Componentes e gráficos',ratio>=3]];q('#contrast-table').innerHTML=tests.map(([name,pass])=>`<tr><td>${name}</td><td><strong>${pass?'✓ Aprovado':'✕ Reprovado'}</strong></td></tr>`).join('');q('#contrast-summary').textContent=ratio>=4.5?'Bom contraste para texto normal.':'Aumente a diferença entre as cores para texto normal.';showStatus('Contraste calculado segundo as proporções da WCAG. ',ratio>=4.5?'success':'warning');trackAction('check_contrast',{ratio:Number(ratio.toFixed(2))});};
    [['#color-foreground-picker','#color-foreground'],['#color-background-picker','#color-background']].forEach(([picker,text])=>{q(picker).addEventListener('input',()=>{q(text).value=q(picker).value;update();});q(text).addEventListener('input',update);});q('#swap-colors').addEventListener('click',()=>{const fg=q('#color-foreground').value;q('#color-foreground').value=q('#color-background').value;q('#color-background').value=fg;update();});update();
  }

  function redimensionarImagem() {
    html(`<div class="field"><label for="image-file">Imagem JPG, PNG ou WebP</label><input class="input" id="image-file" type="file" accept="image/jpeg,image/png,image/webp"></div><div class="three-col"><div class="field"><label for="image-width">Largura máxima</label><input class="input" id="image-width" type="number" min="1" max="12000" value="1600"></div><div class="field"><label for="image-height">Altura máxima</label><input class="input" id="image-height" type="number" min="1" max="12000" value="1600"></div><div class="field"><label for="image-format">Formato</label><select id="image-format"><option value="image/webp">WebP</option><option value="image/jpeg">JPEG</option><option value="image/png">PNG</option></select></div></div><div class="field"><label for="image-quality">Qualidade: <span id="quality-label">85%</span></label><input id="image-quality" type="range" min="10" max="100" value="85"></div><div class="options-row"><label class="check"><input id="image-upscale" type="checkbox"> Permitir ampliar imagens pequenas</label></div><div class="actions"><button class="btn btn-primary" id="resize-image">Redimensionar</button><button class="btn btn-secondary" id="download-image" disabled>Baixar imagem</button></div><div class="preview-box" id="image-preview-box"><p>Selecione uma imagem. O arquivo será processado somente no navegador.</p></div><div class="metric-grid" id="image-metrics"></div><div class="status" id="status"></div>`);
    let source=null,resultBlob=null,resultName='imagem-redimensionada.webp';
    q('#image-quality').addEventListener('input',()=>q('#quality-label').textContent=`${q('#image-quality').value}%`);
    q('#image-file').addEventListener('change',()=>{const file=q('#image-file').files[0];resultBlob=null;q('#download-image').disabled=true;if(!file)return;if(file.size>25*1024*1024)return showStatus('Escolha um arquivo de até 25 MB.','error');const reader=new FileReader();reader.onload=()=>{const image=new Image();image.onload=()=>{source={image,file,width:image.naturalWidth,height:image.naturalHeight};q('#image-preview-box').innerHTML='';image.className='image-preview';q('#image-preview-box').appendChild(image.cloneNode());q('#image-metrics').innerHTML=`<div class="metric"><strong>${source.width}×${source.height}</strong><span>Dimensões originais</span></div><div class="metric"><strong>${(file.size/1024).toFixed(1)} KB</strong><span>Tamanho original</span></div>`;showStatus('Imagem carregada e pronta para processamento.','success');};image.onerror=()=>showStatus('Não foi possível ler a imagem.','error');image.src=reader.result;};reader.readAsDataURL(file);});
    q('#resize-image').addEventListener('click',async()=>{if(!source)return showStatus('Selecione uma imagem primeiro.','warning');const maxW=clamp(q('#image-width').value,1,12000),maxH=clamp(q('#image-height').value,1,12000),allow=q('#image-upscale').checked;let scale=Math.min(maxW/source.width,maxH/source.height);if(!allow)scale=Math.min(1,scale);const width=Math.max(1,Math.round(source.width*scale)),height=Math.max(1,Math.round(source.height*scale));const canvas=document.createElement('canvas');canvas.width=width;canvas.height=height;const ctx=canvas.getContext('2d',{alpha:q('#image-format').value==='image/png'});if(!ctx)return showStatus('Canvas não está disponível neste navegador.','error');if(q('#image-format').value==='image/jpeg'){ctx.fillStyle='#fff';ctx.fillRect(0,0,width,height);}ctx.imageSmoothingEnabled=true;ctx.imageSmoothingQuality='high';ctx.drawImage(source.image,0,0,width,height);const type=q('#image-format').value,quality=Number(q('#image-quality').value)/100;resultBlob=await new Promise(resolve=>canvas.toBlob(resolve,type,quality));if(!resultBlob)return showStatus('Não foi possível gerar o arquivo.','error');const ext=type==='image/jpeg'?'jpg':type==='image/png'?'png':'webp';resultName=`${source.file.name.replace(/\.[^.]+$/,'')}-${width}x${height}.${ext}`;const url=URL.createObjectURL(resultBlob);const img=new Image();img.src=url;img.className='image-preview';img.onload=()=>setTimeout(()=>URL.revokeObjectURL(url),5000);q('#image-preview-box').innerHTML='';q('#image-preview-box').appendChild(img);q('#image-metrics').innerHTML=`<div class="metric"><strong>${width}×${height}</strong><span>Novas dimensões</span></div><div class="metric"><strong>${(source.file.size/1024).toFixed(1)} KB</strong><span>Original</span></div><div class="metric"><strong>${(resultBlob.size/1024).toFixed(1)} KB</strong><span>Resultado</span></div><div class="metric"><strong>${Math.round((1-resultBlob.size/source.file.size)*100)}%</strong><span>Variação de tamanho</span></div>`;q('#download-image').disabled=false;showStatus('Imagem processada localmente. Confira a prévia antes de baixar.','success');trackAction('resize_image',{width,height,format:type});});
    q('#download-image').addEventListener('click',()=>{if(!resultBlob)return;downloadText(resultBlob,resultName,resultBlob.type);trackAction('download_result',{format:resultBlob.type});});
  }

  const rootPath = document.body?.dataset.root || '';
  const fileToBuffer = (file) => file.arrayBuffer();
  const bytesLabel = (n) => n < 1024 ? `${n} B` : n < 1024 ** 2 ? `${(n/1024).toFixed(1)} KB` : `${(n/1024**2).toFixed(1)} MB`;
  const downloadBlob = (blob, name) => downloadText(blob, name, blob.type || 'application/octet-stream');
  const canvasToBlob = (canvas, type='image/png', quality=.92) => new Promise(resolve => canvas.toBlob(resolve, type, quality));
  const loadImageFile = (file) => new Promise((resolve, reject) => {
    const url = URL.createObjectURL(file); const img = new Image();
    img.onload = () => { URL.revokeObjectURL(url); resolve(img); };
    img.onerror = () => { URL.revokeObjectURL(url); reject(new Error('Não foi possível ler a imagem.')); };
    img.src = url;
  });
  let pdfJsPromise;
  const loadPdfJs = async () => {
    if (!pdfJsPromise) pdfJsPromise = import(new URL(`${rootPath}assets/vendor/pdfjs/pdf.min.mjs`, document.baseURI).href).then(mod => {
      mod.GlobalWorkerOptions.workerSrc = new URL(`${rootPath}assets/vendor/pdfjs/pdf.worker.min.mjs`, document.baseURI).href;
      return mod;
    });
    return pdfJsPromise;
  };
  const parsePages = (spec, total) => {
    const text = String(spec || '').trim();
    if (!text) return Array.from({length: total}, (_, i) => i);
    const out = [];
    for (const token of text.split(',').map(x => x.trim()).filter(Boolean)) {
      if (/^\d+$/.test(token)) out.push(Number(token)-1);
      else {
        const m = token.match(/^(\d+)\s*-\s*(\d+)$/);
        if (!m) throw new Error(`Intervalo inválido: ${token}`);
        const a = Number(m[1]), b = Number(m[2]), step = a <= b ? 1 : -1;
        for (let n=a; step>0 ? n<=b : n>=b; n+=step) out.push(n-1);
      }
    }
    const unique = [...new Set(out)];
    if (!unique.length || unique.some(i => i < 0 || i >= total)) throw new Error(`Use páginas entre 1 e ${total}.`);
    return unique;
  };
  const cryptoShuffle = (items) => {
    const a=[...items];
    for(let i=a.length-1;i>0;i--){const j=randomInt(i+1);[a[i],a[j]]=[a[j],a[i]];}
    return a;
  };
  const normalizeLines = (text) => String(text || '').replace(/\r\n?/g,'\n').split('\n');
  const escapeRegExp = (s) => String(s).replace(/[.*+?^${}()|[\]\\]/g,'\\$&');

  function juntarPdf() {
    html(`<div class="field"><label for="merge-files">Arquivos PDF</label><input class="input" id="merge-files" type="file" accept="application/pdf" multiple></div><div id="merge-list" class="file-list empty-state">Selecione dois ou mais PDFs.</div><div class="actions"><button class="btn btn-primary" id="merge-run">Juntar PDFs</button><button class="btn btn-secondary" id="merge-download" disabled>Baixar resultado</button></div><div class="status" id="status"></div>`);
    let files=[], blob=null;
    const render=()=>{q('#merge-list').className=files.length?'file-list':'file-list empty-state';q('#merge-list').innerHTML=files.length?files.map((f,i)=>`<div class="file-row"><div><strong>${escapeHtml(f.name)}</strong><small>${bytesLabel(f.size)}</small></div><div><button class="mini-btn" data-up="${i}" ${i===0?'disabled':''}>↑</button><button class="mini-btn" data-down="${i}" ${i===files.length-1?'disabled':''}>↓</button><button class="mini-btn danger" data-remove="${i}">Remover</button></div></div>`).join(''):'Selecione dois ou mais PDFs.';};
    q('#merge-files').addEventListener('change',()=>{files=[...q('#merge-files').files];blob=null;q('#merge-download').disabled=true;render();});
    q('#merge-list').addEventListener('click',e=>{const b=e.target.closest('button');if(!b)return;const idx=Number(b.dataset.up ?? b.dataset.down ?? b.dataset.remove);if('up'in b.dataset&&idx>0)[files[idx-1],files[idx]]=[files[idx],files[idx-1]];if('down'in b.dataset&&idx<files.length-1)[files[idx+1],files[idx]]=[files[idx],files[idx+1]];if('remove'in b.dataset)files.splice(idx,1);blob=null;q('#merge-download').disabled=true;render();});
    q('#merge-run').addEventListener('click',async()=>{const btn=q('#merge-run');try{if(files.length<2)throw new Error('Selecione pelo menos dois PDFs.');if(!window.PDFLib)throw new Error('Biblioteca de PDF não carregada.');setBusy(btn,true);const out=await PDFLib.PDFDocument.create();for(const file of files){const src=await PDFLib.PDFDocument.load(await fileToBuffer(file));const pages=await out.copyPages(src,src.getPageIndices());pages.forEach(p=>out.addPage(p));}blob=new Blob([await out.save()],{type:'application/pdf'});q('#merge-download').disabled=false;showStatus(`PDF criado com ${out.getPageCount()} páginas (${bytesLabel(blob.size)}).`,'success');trackAction('merge_pdf',{file_count:files.length,page_count:out.getPageCount()});}catch(err){showStatus(err.message,'error');}finally{setBusy(btn,false);}});
    q('#merge-download').addEventListener('click',()=>blob&&downloadBlob(blob,'pdfs-unidos.pdf'));render();
  }

  function separarPdf() {
    html(`<div class="field"><label for="split-file">Arquivo PDF</label><input class="input" id="split-file" type="file" accept="application/pdf"></div><div class="two-col"><div class="field"><label for="split-pages">Páginas</label><input class="input" id="split-pages" placeholder="Ex.: 1-3, 5, 8"></div><div class="field"><label for="split-mode">Resultado</label><select id="split-mode"><option value="single">Um PDF com as páginas</option><option value="zip">Um PDF por página em ZIP</option></select></div></div><div class="actions"><button class="btn btn-primary" id="split-run">Separar</button><button class="btn btn-secondary" id="split-download" disabled>Baixar</button></div><div class="status" id="status"></div><p class="note">Deixe o campo de páginas vazio para usar todas as páginas.</p>`);
    let blob=null,name='paginas-extraidas.pdf';
    q('#split-run').addEventListener('click',async()=>{const btn=q('#split-run');try{const file=q('#split-file').files[0];if(!file)throw new Error('Selecione um PDF.');setBusy(btn,true);const src=await PDFLib.PDFDocument.load(await fileToBuffer(file));const indexes=parsePages(q('#split-pages').value,src.getPageCount());if(q('#split-mode').value==='single'){const out=await PDFLib.PDFDocument.create();(await out.copyPages(src,indexes)).forEach(p=>out.addPage(p));blob=new Blob([await out.save()],{type:'application/pdf'});name='paginas-extraidas.pdf';}else{if(!window.JSZip)throw new Error('Biblioteca ZIP não carregada.');const zip=new JSZip();for(const idx of indexes){const out=await PDFLib.PDFDocument.create();const [p]=await out.copyPages(src,[idx]);out.addPage(p);zip.file(`pagina-${String(idx+1).padStart(3,'0')}.pdf`,await out.save());}blob=await zip.generateAsync({type:'blob'});name='paginas-separadas.zip';}q('#split-download').disabled=false;showStatus(`${indexes.length} página(s) preparada(s): ${bytesLabel(blob.size)}.`,'success');trackAction('split_pdf',{page_count:indexes.length,mode:q('#split-mode').value});}catch(err){showStatus(err.message,'error');}finally{setBusy(btn,false);}});
    q('#split-download').addEventListener('click',()=>blob&&downloadBlob(blob,name));
  }

  function organizarPdf() {
    html(`<div class="field"><label for="organize-file">Arquivo PDF</label><input class="input" id="organize-file" type="file" accept="application/pdf"></div><div id="organize-pages" class="pdf-page-list empty-state">Selecione um PDF para visualizar as páginas.</div><div class="actions"><button class="btn btn-primary" id="organize-run" disabled>Gerar PDF organizado</button><button class="btn btn-secondary" id="organize-download" disabled>Baixar</button></div><div class="status" id="status"></div>`);
    let sourceBytes=null,pages=[],blob=null;
    const render=()=>{q('#organize-pages').className=pages.length?'pdf-page-list':'pdf-page-list empty-state';q('#organize-pages').innerHTML=pages.length?pages.map((p,i)=>`<div class="pdf-page-item" draggable="true" data-index="${i}"><canvas data-thumb="${i}"></canvas><strong>Página ${p.original+1}</strong><div><button class="mini-btn" data-left="${i}" ${i===0?'disabled':''}>←</button><button class="mini-btn" data-right="${i}" ${i===pages.length-1?'disabled':''}>→</button><button class="mini-btn danger" data-delete="${i}">Excluir</button></div></div>`).join(''):'Selecione um PDF para visualizar as páginas.';};
    const thumbs=async()=>{if(!sourceBytes||!pages.length)return;const pdfjs=await loadPdfJs();const doc=await pdfjs.getDocument({data:sourceBytes.slice(0)}).promise;for(let i=0;i<pages.length;i++){const c=q(`[data-thumb="${i}"]`);if(!c)continue;const page=await doc.getPage(pages[i].original+1),vp=page.getViewport({scale:.25});c.width=vp.width;c.height=vp.height;await page.render({canvasContext:c.getContext('2d'),viewport:vp}).promise;}};
    q('#organize-file').addEventListener('change',async()=>{try{const f=q('#organize-file').files[0];if(!f)return;sourceBytes=new Uint8Array(await fileToBuffer(f));const src=await PDFLib.PDFDocument.load(sourceBytes.slice(0));pages=src.getPageIndices().map(original=>({original}));render();await thumbs();q('#organize-run').disabled=false;showStatus(`${pages.length} páginas carregadas.`,'success');}catch(err){showStatus(err.message,'error');}});
    q('#organize-pages').addEventListener('click',async e=>{const b=e.target.closest('button');if(!b)return;const i=Number(b.dataset.left??b.dataset.right??b.dataset.delete);if('left'in b.dataset&&i>0)[pages[i-1],pages[i]]=[pages[i],pages[i-1]];if('right'in b.dataset&&i<pages.length-1)[pages[i+1],pages[i]]=[pages[i],pages[i+1]];if('delete'in b.dataset)pages.splice(i,1);blob=null;q('#organize-download').disabled=true;render();await thumbs();});
    q('#organize-run').addEventListener('click',async()=>{try{if(!pages.length)throw new Error('Mantenha pelo menos uma página.');const src=await PDFLib.PDFDocument.load(sourceBytes.slice(0)),out=await PDFLib.PDFDocument.create();(await out.copyPages(src,pages.map(p=>p.original))).forEach(p=>out.addPage(p));blob=new Blob([await out.save()],{type:'application/pdf'});q('#organize-download').disabled=false;showStatus(`Novo PDF criado com ${pages.length} páginas.`,'success');trackAction('organize_pdf',{page_count:pages.length});}catch(err){showStatus(err.message,'error');}});
    q('#organize-download').addEventListener('click',()=>blob&&downloadBlob(blob,'pdf-organizado.pdf'));
  }

  function imagensParaPdf() {
    html(`<div class="field"><label for="imgpdf-files">Imagens JPG, PNG ou WebP</label><input class="input" id="imgpdf-files" type="file" accept="image/jpeg,image/png,image/webp" multiple></div><div class="three-col"><div class="field"><label for="imgpdf-size">Página</label><select id="imgpdf-size"><option value="a4">A4</option><option value="original">Tamanho da imagem</option></select></div><div class="field"><label for="imgpdf-orientation">Orientação</label><select id="imgpdf-orientation"><option value="auto">Automática</option><option value="portrait">Retrato</option><option value="landscape">Paisagem</option></select></div><div class="field"><label for="imgpdf-margin">Margem (mm)</label><input class="input" id="imgpdf-margin" type="number" min="0" max="50" value="10"></div></div><div id="imgpdf-list" class="file-list empty-state">Selecione uma ou mais imagens.</div><div class="actions"><button class="btn btn-primary" id="imgpdf-run">Criar PDF</button><button class="btn btn-secondary" id="imgpdf-download" disabled>Baixar PDF</button></div><div class="status" id="status"></div>`);
    let files=[],blob=null;
    const render=()=>q('#imgpdf-list').innerHTML=files.length?files.map((f,i)=>`<div class="file-row"><div><strong>${escapeHtml(f.name)}</strong><small>${bytesLabel(f.size)}</small></div><div><button class="mini-btn" data-up="${i}" ${i===0?'disabled':''}>↑</button><button class="mini-btn" data-down="${i}" ${i===files.length-1?'disabled':''}>↓</button><button class="mini-btn danger" data-remove="${i}">Remover</button></div></div>`).join(''):'Selecione uma ou mais imagens.';
    q('#imgpdf-files').addEventListener('change',()=>{files=[...q('#imgpdf-files').files];blob=null;q('#imgpdf-download').disabled=true;render();});
    q('#imgpdf-list').addEventListener('click',e=>{const b=e.target.closest('button');if(!b)return;const i=Number(b.dataset.up??b.dataset.down??b.dataset.remove);if('up'in b.dataset&&i>0)[files[i-1],files[i]]=[files[i],files[i-1]];if('down'in b.dataset&&i<files.length-1)[files[i+1],files[i]]=[files[i],files[i+1]];if('remove'in b.dataset)files.splice(i,1);render();});
    q('#imgpdf-run').addEventListener('click',async()=>{const btn=q('#imgpdf-run');try{if(!files.length)throw new Error('Selecione imagens.');setBusy(btn,true);const pdf=await PDFLib.PDFDocument.create(),mm=2.834645669,margin=clamp(q('#imgpdf-margin').value,0,50)*mm;for(const f of files){const bytes=await fileToBuffer(f);let embedded;if(f.type==='image/png')embedded=await pdf.embedPng(bytes);else if(f.type==='image/jpeg')embedded=await pdf.embedJpg(bytes);else{const img=await loadImageFile(f),canvas=document.createElement('canvas');canvas.width=img.naturalWidth;canvas.height=img.naturalHeight;canvas.getContext('2d').drawImage(img,0,0);const png=await canvasToBlob(canvas,'image/png');embedded=await pdf.embedPng(await png.arrayBuffer());}let pw,ph;if(q('#imgpdf-size').value==='original'){pw=embedded.width;ph=embedded.height;}else{pw=595.28;ph=841.89;const o=q('#imgpdf-orientation').value;if(o==='landscape'||(o==='auto'&&embedded.width>embedded.height))[pw,ph]=[ph,pw];}const scale=Math.min((pw-2*margin)/embedded.width,(ph-2*margin)/embedded.height),w=embedded.width*scale,h=embedded.height*scale;const page=pdf.addPage([pw,ph]);page.drawImage(embedded,{x:(pw-w)/2,y:(ph-h)/2,width:w,height:h});}blob=new Blob([await pdf.save()],{type:'application/pdf'});q('#imgpdf-download').disabled=false;showStatus(`PDF criado com ${files.length} páginas (${bytesLabel(blob.size)}).`,'success');trackAction('images_to_pdf',{file_count:files.length});}catch(err){showStatus(err.message,'error');}finally{setBusy(btn,false);}});
    q('#imgpdf-download').addEventListener('click',()=>blob&&downloadBlob(blob,'imagens.pdf'));render();
  }

