    let blob=null;
    q('#pdfimg-run').addEventListener('click',async()=>{const btn=q('#pdfimg-run');try{const file=q('#pdfimg-file').files[0];if(!file)throw new Error('Selecione um PDF.');setBusy(btn,true);const pdfjs=await loadPdfJs(),doc=await pdfjs.getDocument({data:new Uint8Array(await fileToBuffer(file))}).promise,indexes=parsePages(q('#pdfimg-pages').value,doc.numPages),zip=new JSZip(),format=q('#pdfimg-format').value,ext=format==='image/png'?'png':'jpg',quality=.9;q('#pdfimg-preview').innerHTML='';for(const idx of indexes){const page=await doc.getPage(idx+1),vp=page.getViewport({scale:Number(q('#pdfimg-scale').value)}),canvas=document.createElement('canvas');canvas.width=Math.ceil(vp.width);canvas.height=Math.ceil(vp.height);await page.render({canvasContext:canvas.getContext('2d'),viewport:vp}).promise;const imgBlob=await canvasToBlob(canvas,format,quality);zip.file(`pagina-${String(idx+1).padStart(3,'0')}.${ext}`,imgBlob);const img=document.createElement('img');img.src=URL.createObjectURL(imgBlob);img.alt=`Página ${idx+1}`;q('#pdfimg-preview').appendChild(img);}blob=await zip.generateAsync({type:'blob'});q('#pdfimg-download').disabled=false;showStatus(`${indexes.length} página(s) convertida(s).`,'success');trackAction('pdf_to_images',{page_count:indexes.length,format:ext});}catch(err){showStatus(err.message,'error');}finally{setBusy(btn,false);}});
    q('#pdfimg-download').addEventListener('click',()=>blob&&downloadBlob(blob,'paginas-do-pdf.zip'));
