  function comprimirImagem() {
    html(`<div class="field"><label for="compress-file">Imagem</label><input class="input" id="compress-file" type="file" accept="image/jpeg,image/png,image/webp"></div><div class="three-col"><div class="field"><label for="compress-format">Formato</label><select id="compress-format"><option value="image/webp">WebP</option><option value="image/jpeg">JPEG</option><option value="image/png">PNG</option></select></div><div class="field"><label for="compress-quality">Qualidade <span id="compress-quality-label">82%</span></label><input id="compress-quality" type="range" min="10" max="100" value="82"></div><div class="field"><label for="compress-max">Largura máxima</label><input class="input" id="compress-max" type="number" min="100" max="12000" value="2400"></div></div><div class="actions"><button class="btn btn-primary" id="compress-run">Comprimir</button><button class="btn btn-secondary" id="compress-download" disabled>Baixar</button></div><div id="compress-preview" class="preview-box">Selecione uma imagem.</div><div class="metric-grid" id="compress-metrics"></div><div class="status" id="status"></div>`);
    let blob=null,name='imagem-compactada.webp';q('#compress-quality').addEventListener('input',()=>q('#compress-quality-label').textContent=`${q('#compress-quality').value}%`);
    q('#compress-run').addEventListener('click',async()=>{try{const file=q('#compress-file').files[0];if(!file)throw new Error('Selecione uma imagem.');const img=await loadImageFile(file),max=clamp(q('#compress-max').value,100,12000),scale=Math.min(1,max/img.naturalWidth),canvas=document.createElement('canvas');canvas.width=Math.round(img.naturalWidth*scale);canvas.height=Math.round(img.naturalHeight*scale);const ctx=canvas.getContext('2d');if(q('#compress-format').value==='image/jpeg'){ctx.fillStyle='#fff';ctx.fillRect(0,0,canvas.width,canvas.height);}ctx.drawImage(img,0,0,canvas.width,canvas.height);blob=await canvasToBlob(canvas,q('#compress-format').value,Number(q('#compress-quality').value)/100);if(!blob)throw new Error('Falha ao gerar a imagem.');const ext=blob.type==='image/jpeg'?'jpg':blob.type==='image/png'?'png':'webp';name=`${file.name.replace(/\.[^.]+$/,'')}-compactada.${ext}`;q('#compress-preview').innerHTML='';const preview=new Image();preview.src=URL.createObjectURL(blob);preview.className='image-preview';q('#compress-preview').appendChild(preview);const delta=Math.round((1-blob.size/file.size)*100);q('#compress-metrics').innerHTML=`<div class="metric"><strong>${bytesLabel(file.size)}</strong><span>Original</span></div><div class="metric"><strong>${bytesLabel(blob.size)}</strong><span>Resultado</span></div><div class="metric"><strong>${delta}%</strong><span>Redução estimada</span></div>`;q('#compress-download').disabled=false;showStatus('Imagem processada. Compare a prévia antes de baixar.',delta>=0?'success':'warning');trackAction('compress_image',{reduction:delta});}catch(err){showStatus(err.message,'error');}});
    q('#compress-download').addEventListener('click',()=>blob&&downloadBlob(blob,name));
  }

