  function imagemBase64() {
    html(`<div class="tabs"><button class="tab active" data-tab="encode">Imagem → Base64</button><button class="tab" data-tab="decode">Base64 → imagem</button></div><div data-pane="encode"><div class="field"><label for="img64-file">Imagem</label><input class="input" id="img64-file" type="file" accept="image/*"></div><div class="actions"><button class="btn btn-primary" id="img64-encode">Converter</button><button class="btn btn-secondary" data-copy-target="#img64-output">Copiar</button></div><textarea id="img64-output" class="output-input" readonly></textarea></div><div data-pane="decode" hidden><div class="field"><label for="img64-input">Data URL ou Base64</label><textarea id="img64-input" placeholder="data:image/png;base64,..."></textarea></div><div class="actions"><button class="btn btn-primary" id="img64-decode">Visualizar</button><button class="btn btn-secondary" id="img64-download" disabled>Baixar imagem</button></div><div class="preview-box" id="img64-preview"></div></div><div class="status" id="status"></div>`);
    let blob=null,name='imagem.png';qa('.tab').forEach(b=>b.addEventListener('click',()=>{qa('.tab').forEach(x=>x.classList.toggle('active',x===b));qa('[data-pane]').forEach(p=>p.hidden=p.dataset.pane!==b.dataset.tab);}));
    q('#img64-encode').addEventListener('click',()=>{const f=q('#img64-file').files[0];if(!f)return showStatus('Selecione uma imagem.','warning');const r=new FileReader();r.onload=()=>{q('#img64-output').value=r.result;showStatus(`Data URL gerada com ${String(r.result).length} caracteres.`,'success');trackAction('image_to_base64');};r.readAsDataURL(f);});
    q('#img64-decode').addEventListener('click',async()=>{try{let value=q('#img64-input').value.trim();if(!value)throw new Error('Cole um conteúdo Base64.');if(!value.startsWith('data:'))value=`data:image/png;base64,${value.replace(/\s/g,'')}`;const res=await fetch(value);blob=await res.blob();if(!blob.type.startsWith('image/'))throw new Error('O conteúdo não representa uma imagem.');name=`imagem.${blob.type.split('/')[1].replace('jpeg','jpg')}`;const img=new Image();img.src=URL.createObjectURL(blob);img.className='image-preview';q('#img64-preview').innerHTML='';q('#img64-preview').appendChild(img);q('#img64-download').disabled=false;showStatus(`Imagem reconhecida: ${blob.type}.`,'success');trackAction('base64_to_image');}catch(err){showStatus(err.message,'error');}});q('#img64-download').addEventListener('click',()=>blob&&downloadBlob(blob,name));
  }

