  function calculadoraIdade() {
    const today=new Date(),birth=new Date(today.getFullYear()-30,today.getMonth(),today.getDate());html(`<div class="two-col"><div class="field"><label for="age-birth">Data de nascimento</label><input class="input" id="age-birth" type="date" value="${isoDate(birth)}"></div><div class="field"><label for="age-ref">Data de referência</label><input class="input" id="age-ref" type="date" value="${isoDate(today)}"></div></div><div class="actions"><button class="btn btn-primary" id="age-run">Calcular idade</button></div><div class="result-hero" id="age-result"></div><div class="metric-grid" id="age-metrics"></div><div class="status" id="status"></div>`);const run=()=>{const b=localDate(q('#age-birth').value),r=localDate(q('#age-ref').value);if(Number.isNaN(b.getTime())||Number.isNaN(r.getTime()))return showStatus('Escolha datas válidas.','error');if(b>r)return showStatus('Nascimento não pode ser posterior à referência.','error');let y=r.getFullYear()-b.getFullYear(),m=r.getMonth()-b.getMonth(),d=r.getDate()-b.getDate();if(d<0){m--;d+=new Date(r.getFullYear(),r.getMonth(),0).getDate();}if(m<0){y--;m+=12;}const total=Math.floor((r-b)/86400000);q('#age-result').textContent=`${y} anos, ${m} meses e ${d} dias`;q('#age-metrics').innerHTML=`<div class="metric"><strong>${total.toLocaleString('pt-BR')}</strong><span>Dias vividos até a referência</span></div><div class="metric"><strong>${Math.floor(total/7).toLocaleString('pt-BR')}</strong><span>Semanas completas</span></div>`;showStatus('Idade calculada pelo calendário.','success');trackAction('calculate_age');};q('#age-run').addEventListener('click',run);run();
  }

