  function sorteador() {
    html(`<div class="tabs"><button class="tab active" data-mode="list">Lista</button><button class="tab" data-mode="numbers">Números</button></div><div data-pane="list"><div class="field"><label for="draw-list">Um item por linha</label><textarea id="draw-list">Cenário de login\nCadastro válido\nSenha inválida\nSessão expirada</textarea></div></div><div data-pane="numbers" hidden><div class="three-col"><div class="field"><label for="draw-min">Mínimo</label><input class="input" id="draw-min" type="number" value="1"></div><div class="field"><label for="draw-max">Máximo</label><input class="input" id="draw-max" type="number" value="100"></div><div class="field"><label for="draw-count">Quantidade</label><input class="input" id="draw-count" type="number" min="1" value="1"></div></div></div><div class="options-row"><label class="check"><input id="draw-unique" type="checkbox" checked> Sem repetição</label></div><div class="actions"><button class="btn btn-primary" id="draw-run">Sortear</button><button class="btn btn-secondary" data-copy-target="#draw-result">Copiar</button></div><pre class="output large" id="draw-result"></pre><div class="status" id="status"></div>`);let mode='list';qa('.tab').forEach(b=>b.addEventListener('click',()=>{mode=b.dataset.mode;qa('.tab').forEach(x=>x.classList.toggle('active',x===b));qa('[data-pane]').forEach(p=>p.hidden=p.dataset.pane!==mode);}));q('#draw-run').addEventListener('click',()=>{try{let result=[];if(mode==='list'){const items=normalizeLines(q('#draw-list').value).map(x=>x.trim()).filter(Boolean);if(!items.length)throw new Error('Informe itens.');result=cryptoShuffle(items).slice(0,1);}else{let min=Math.ceil(Number(q('#draw-min').value)),max=Math.floor(Number(q('#draw-max').value)),count=Math.floor(clamp(q('#draw-count').value,1,1000));if(min>max)[min,max]=[max,min];const range=max-min+1;if(q('#draw-unique').checked&&count>range)throw new Error('Quantidade maior que o intervalo sem repetição.');if(q('#draw-unique').checked)result=cryptoShuffle(Array.from({length:range},(_,i)=>min+i)).slice(0,count);else result=Array.from({length:count},()=>min+randomInt(range));}q('#draw-result').textContent=result.join('\n');showStatus('Sorteio concluído com aleatoriedade do navegador.','success');trackAction('draw_items',{mode,count:result.length});}catch(err){showStatus(err.message,'error');}});q('#draw-run').click();
  }

